sql_examples.sql:
-- 기본 위치에 SPFILE 생성
CREATE SPFILE FROM PFILE;

-- 경로 지정하여 생성
CREATE SPFILE = '/u01/app/oracle/dbs/spfileORCL.ora'
  FROM PFILE = '/u01/app/oracle/dbs/initORCL.ora';

-- SPFILE을 텍스트 형태로 추출
CREATE PFILE FROM SPFILE;

-- 특정 경로에 추출
CREATE PFILE = '/tmp/initORCL_backup.ora' FROM SPFILE;

-- 원격 SPFILE에서 메모리 기반 PFILE 추출
CREATE PFILE FROM MEMORY;

-- SCOPE=BOTH (기본) — 메모리 + SPFILE 동시 반영
ALTER SYSTEM SET open_cursors = 500 SCOPE=BOTH;

-- SCOPE=MEMORY — 메모리에만 반영 (재기동 시 사라짐)
ALTER SYSTEM SET open_cursors = 500 SCOPE=MEMORY;

-- SCOPE=SPFILE — SPFILE에만 기록 (다음 기동 시 적용)
ALTER SYSTEM SET open_cursors = 500 SCOPE=SPFILE;

-- 정적 파라미터 (SCOPE=SPFILE만 가능)
ALTER SYSTEM SET processes = 500 SCOPE=SPFILE;

-- SPFILE에서 파라미터 제거 (기본값으로 복원)
ALTER SYSTEM RESET open_cursors SCOPE=SPFILE SID='*';

-- 특정 인스턴스의 파라미터만 제거 (RAC)
ALTER SYSTEM RESET open_cursors SCOPE=SPFILE SID='orcl1';
